```rust
//! Theme mapping layer between dcg Theme and rich_rust Style.
//!
//! dcg has an existing theme system in theme.rs using ratatui::style::Color.
//! This module provides conversion functions to rich_rust's Style system.

#[cfg(feature = "rich-output")]
use rich_rust::prelude::*;

use crate::output::theme::{BorderStyle, Severity, Theme, ThemePalette};
use ratatui::style::Color as RatColor;

/// Convert ratatui Color to rich_rust color string for markup.
#[cfg(feature = "rich-output")]
pub fn color_to_markup(color: RatColor) -> &'static str {
    match color {
        RatColor::Reset => "",
        RatColor::Black => "black",
        RatColor::Red => "red",
        RatColor::Green => "green",
        RatColor::Yellow => "yellow",
        RatColor::Blue => "blue",
        RatColor::Magenta => "magenta",
        RatColor::Cyan => "cyan",
        RatColor::Gray => "bright_black",
        RatColor::DarkGray => "bright_black",
        RatColor::LightRed => "bright_red",
        RatColor::LightGreen => "bright_green",
        RatColor::LightYellow => "bright_yellow",
        RatColor::LightBlue => "bright_blue",
        RatColor::LightMagenta => "bright_magenta",
        RatColor::LightCyan => "bright_cyan",
        RatColor::White => "white",
        RatColor::Rgb(_, _, _) | RatColor::Indexed(_) => "white", // Fallback
    }
}

/// Convert Severity to rich_rust markup style string.
#[cfg(feature = "rich-output")]
pub fn severity_to_style(severity: Severity) -> &'static str {
    match severity {
        Severity::Critical => "bold bright_red",
        Severity::High => "red",
        Severity::Medium => "yellow",
        Severity::Low => "blue",
    }
}

/// Convert Severity to appropriate BoxStyle.
#[cfg(feature = "rich-output")]
pub fn severity_to_box_style(severity: Severity) -> BoxStyle {
    match severity {
        Severity::Critical => BoxStyle::double(),  // ╔═╗
        Severity::High => BoxStyle::heavy(),       // ┏━┓
        Severity::Medium => BoxStyle::rounded(),   // ╭─╮
        Severity::Low => BoxStyle::rounded(),      // ╭─╮
    }
}

/// Convert dcg BorderStyle to rich_rust BoxStyle.
#[cfg(feature = "rich-output")]
pub fn border_to_box_style(border: BorderStyle) -> BoxStyle {
    match border {
        BorderStyle::Unicode => BoxStyle::rounded(),
        BorderStyle::Ascii => BoxStyle::ascii(),
        BorderStyle::None => BoxStyle::minimal(),
    }
}

/// Extension trait for Theme to get rich_rust styles.
#[cfg(feature = "rich-output")]
pub trait RichThemeExt {
    /// Get rich_rust Style for error text.
    fn rich_error_style(&self) -> Style;

    /// Get rich_rust Style for warning text.
    fn rich_warning_style(&self) -> Style;

    /// Get rich_rust Style for success text.
    fn rich_success_style(&self) -> Style;

    /// Get rich_rust Style for muted/dim text.
    fn rich_muted_style(&self) -> Style;

    /// Get rich_rust Style for a given severity.
    fn rich_severity_style(&self, severity: Severity) -> Style;
}

#[cfg(feature = "rich-output")]
impl RichThemeExt for Theme {
    fn rich_error_style(&self) -> Style {
        Style::parse(color_to_markup(self.error_color))
            .unwrap_or_default()
            .bold()
    }

    fn rich_warning_style(&self) -> Style {
        Style::parse(color_to_markup(self.warning_color))
            .unwrap_or_default()
    }

    fn rich_success_style(&self) -> Style {
        Style::parse(color_to_markup(self.success_color))
            .unwrap_or_default()
    }

    fn rich_muted_style(&self) -> Style {
        Style::new().dim()
    }

    fn rich_severity_style(&self, severity: Severity) -> Style {
        let color = self.color_for_severity(severity);
        let mut style = Style::parse(color_to_markup(color)).unwrap_or_default();

        if matches!(severity, Severity::Critical) {
            style = style.bold();
        }

        style
    }
}

/// Color palette mapping for reference.
///
/// | dcg Theme Color    | rich_rust Markup   | Used For                |
/// |--------------------|-------------------|-------------------------|
/// | error_color        | bright_red        | Blocked messages        |
/// | warning_color      | yellow            | Warnings, medium sev    |
/// | success_color      | bright_green      | Allowed messages        |
/// | info_color         | cyan              | Info, pack names        |
/// | muted_color        | dim               | Explanatory text        |
/// | critical_severity  | bold bright_red   | Critical severity       |
/// | high_severity      | red               | High severity           |
/// | medium_severity    | yellow            | Medium severity         |
/// | low_severity       | blue              | Low severity            |
```

### Why This Layer Exists

1. **Gradual Migration**: Don't need to change all theme.rs callers at once
2. **Consistency**: Single source of truth for color mappings
3. **Testability**: Can test mappings in isolation
4. **Flexibility**: Can adjust mappings without touching rich_rust

### Tests

